      </div>

      {/* Related Products */}
      <div className="mt-8">
        <h2 className="text-2xl font-bold tracking-tight mb-6">More like this</h2>
        <div className="grid grid-cols-2 gap-4 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5">
          {relatedProducts.map((p: any) => (
            <Link
              key={p.id}
              to={`/product/${p.id}`}
              className="group rounded-2xl border bg-card/70 p-3 transition-all duration-300 hover:-translate-y-1.5 hover:shadow-xl hover:border-primary/25 pk-glass"
            >
              <div className="aspect-[4/3] overflow-hidden rounded-xl bg-muted mb-3">
                <img src={p.images?.[0] || p.image} alt={p.name} className="h-full w-full object-cover transition duration-500 group-hover:scale-105" />
              </div>
              <div className="text-xs text-muted-foreground font-semibold mb-1">{p.category?.name || p.category}</div>
              <div className="line-clamp-2 text-sm font-semibold leading-snug group-hover:text-primary">{p.name}</div>
              <div className="mt-2 flex items-center gap-1">
                <Star className="h-3.5 w-3.5 fill-amber-400 text-amber-400" />
                <span className="text-xs font-semibold">{(p.averageRating || 0).toFixed(1)}</span>
                <span className="text-xs text-muted-foreground">({p.reviewCount || 0})</span>
              </div>
              <div className="mt-2 text-base font-extrabold text-primary">{formatPriceINR(p.price)}</div>
            </Link>
          ))}
        </div>
      </div>

      {/* Image Zoom Modal */}
      {isZoomed && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm pk-fade-in" onClick={() => setIsZoomed(false)}>
          <div className="relative max-w-4xl w-full p-8" onClick={(e) => e.stopPropagation()}>
            <button
              type="button"
              onClick={() => setIsZoomed(false)}
              className="absolute -top-12 right-0 flex h-10 w-10 items-center justify-center rounded-full bg-white/20 text-white hover:bg-white/30 transition-all"
            >
              ×
            </button>
            <img src={activeImage} alt={product.name} className="w-full h-auto rounded-2xl shadow-2xl" />
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { ArrowRight, Eye, EyeOff, Lock, Mail, Phone, ShoppingBag, User } from 'lucide-react';
import { toast } from 'sonner';
import { useAuthStore } from '../stores/authStore';

export default function Signup() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    phone: '',
    role: 'CUSTOMER' as 'CUSTOMER' | 'SELLER',
  });
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const { signup } = useAuthStore();

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const role = params.get('role') as 'CUSTOMER' | 'SELLER';
    if (role) {
      setFormData(prev => ({ ...prev, role }));
    }
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (formData.password !== formData.confirmPassword) {
      toast.error('Passwords do not match');
      return;
    }

    if (formData.password.length < 6) {
      toast.error('Password must be at least 6 characters');
      return;
    }

    setIsLoading(true);

    try {
      await signup({
        name: formData.name,
        email: formData.email,
        password: formData.password,
        phone: formData.phone || undefined,
        role: formData.role,
      });
      toast.success('Account created successfully!');
    } catch (error: any) {
      toast.error(error.response?.data?.error || 'Signup failed');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="pk-auth-bg min-h-screen flex items-center justify-center py-12 px-4 sm:px-6 lg:px-8 pk-fade-in">
      <div className="w-full max-w-md space-y-6 pk-scale-in">
        <div className="pk-glass rounded-2xl p-8 text-center">
          <div className="mx-auto h-16 w-16 rounded-2xl bg-gradient-to-br from-primary to-brand-4 flex items-center justify-center shadow-lg shadow-primary/30 mb-4">
            <ShoppingBag className="h-8 w-8 text-white" />
          </div>
          <h2 className="text-3xl font-bold">Create your account</h2>
          <p className="mt-2 text-sm text-muted-foreground">
            Already have an account?{' '}
            <Link to="/login" className="font-semibold text-primary hover:opacity-80">
              Sign in
            </Link>
          </p>
        </div>

        <div className="pk-glass rounded-2xl p-8">
          <form className="space-y-5" onSubmit={handleSubmit}>
            <div className="space-y-4">
              <div className="space-y-2">
                <label htmlFor="role" className="text-sm font-medium text-foreground flex items-center gap-2">
                  <User className="h-4 w-4 text-primary" />
                  Account type
                </label>
                <select
                  id="role"
                  name="role"
                  value={formData.role}
                  onChange={handleChange}
                  className="pk-select"
                >
                  <option value="CUSTOMER">Customer - Buy products</option>
                  <option value="SELLER">Seller - Sell products</option>
                </select>
              </div>

              <div className="space-y-2">
                <label htmlFor="name" className="text-sm font-medium text-foreground">Full name</label>
                <input
                  id="name"
                  name="name"
                  type="text"
                  required
                  value={formData.name}
                  onChange={handleChange}
                  className="pk-input"
                  placeholder="Enter your full name"
                />
              </div>

              <div className="space-y-2">
                <label htmlFor="email" className="text-sm font-medium text-foreground flex items-center gap-2">
                  <Mail className="h-4 w-4 text-primary" />
                  Email address
                </label>
                <div className="relative">
                  <input
                    id="email"
                    name="email"
                    type="email"
                    autoComplete="email"
                    required
                    value={formData.email}
                    onChange={handleChange}
                    className="pk-input pl-10"
                    placeholder="Enter your email"
                  />
                  <Mail className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                </div>
              </div>

              <div className="space-y-2">
                <label htmlFor="phone" className="text-sm font-medium text-foreground flex items-center gap-2">
                  <Phone className="h-4 w-4 text-primary" />
                  Phone (optional)
                </label>
                <div className="relative">
                  <input
                    id="phone"
                    name="phone"
                    type="tel"
                    value={formData.phone}
                    onChange={handleChange}
                    className="pk-input pl-10"
                    placeholder="Enter your phone number"
                  />
                  <Phone className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                </div>
              </div>

              <div className="space-y-2">
                <label htmlFor="password" className="text-sm font-medium text-foreground flex items-center gap-2">
                  <Lock className="h-4 w-4 text-primary" />
                  Password
                </label>
                <div className="relative">
                  <input
                    id="password"
                    name="password"
                    type={showPassword ? 'text' : 'password'}
                    required
                    value={formData.password}
                    onChange={handleChange}
                    className="pk-input pl-10 pr-10"
                    placeholder="Create a password"
                  />
                  <Lock className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <button
                    type="button"
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                    onClick={() => setShowPassword(!showPassword)}
                  >
                    {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                  </button>
                </div>
              </div>

              <div className="space-y-2">
                <label htmlFor="confirmPassword" className="text-sm font-medium text-foreground">Confirm password</label>
                <div className="relative">
                  <input
                    id="confirmPassword"
                    name="confirmPassword"
                    type={showConfirmPassword ? 'text' : 'password'}
                    required
                    value={formData.confirmPassword}
                    onChange={handleChange}
                    className="pk-input pr-10"
                    placeholder="Confirm your password"
                  />
                  <button
                    type="button"
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                    onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                  >
                    {showConfirmPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                  </button>
                </div>
              </div>
            </div>

            <div className="flex items-start gap-2 text-sm">
              <input
                id="agree-terms"
                name="agree-terms"
                type="checkbox"
                required
                className="mt-1 h-4 w-4 rounded border-border text-primary focus:ring-primary/30 bg-background/50"
              />
              <label htmlFor="agree-terms" className="text-muted-foreground">
                I agree to the{' '}
                <Link to="/terms" className="font-semibold text-primary hover:opacity-80">
                  Terms
                </Link>{' '}
                and{' '}
                <Link to="/privacy" className="font-semibold text-primary hover:opacity-80">
                  Privacy Policy
                </Link>
              </label>
            </div>

            <button type="submit" disabled={isLoading} className="pk-btn pk-btn-primary pk-btn-shine w-full h-11 text-sm">
              {isLoading ? (
                'Creating account...'
              ) : (
                <span className="flex items-center gap-2">
                  Create account
                  <ArrowRight className="h-4 w-4" />
                </span>
              )}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

import { Link, useNavigate } from 'react-router-dom';
import { useCartStore } from '../stores/cartStore';
import { mockProducts } from '../data/mockProducts';

import { Heart, Sparkles, Trash2, ShoppingCart, Share2, Bell, MoveRight } from 'lucide-react';
import { toast } from 'sonner';

import ProductCard from '../components/products/ProductCard';
import { useState, useMemo } from 'react';

export default function Wishlist() {
  const navigate = useNavigate();
  const wishlistIds = useCartStore((s) => s.wishlist);
  const clearWishlist = useCartStore((s) => s.clearWishlist);
  const addToCart = useCartStore((s) => s.addProductToCart);
  const [sortBy, setSortBy] = useState<'recent' | 'price-low' | 'price-high' | 'name'>('recent');

  const wishlistProducts = useMemo(() => {
    const products = mockProducts.filter(p => wishlistIds.includes(String(p.id)));
    switch (sortBy) {
      case 'price-low': return [...products].sort((a, b) => a.price - b.price);
      case 'price-high': return [...products].sort((a, b) => b.price - a.price);
      case 'name': return [...products].sort((a, b) => a.name.localeCompare(b.name));
      default: return products;
    }
  }, [wishlistIds, sortBy]);

  const handleClearAll = () => {
    if (wishlistProducts.length === 0) return;
    clearWishlist();
    toast.success('Wishlist cleared');
  };

  const handleAddAllToCart = () => {
    wishlistProducts.forEach(p => addToCart(p));
    toast.success(`Added ${wishlistProducts.length} items to cart!`);
    navigate('/cart');
  };

  const handleShare = async () => {
    const url = window.location.href;
    if (navigator.share) {
      await navigator.share({ title: 'My Wishlist', url });
    } else {
      await navigator.clipboard.writeText(url);
      toast.success('Wishlist link copied!');
    }
  };

  if (wishlistProducts.length === 0) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-gradient-to-br from-muted/50 via-background to-muted/30 pk-aurora">
        <div className="relative overflow-hidden rounded-3xl border bg-card/90 p-16 text-center shadow-2xl max-w-lg pk-glass">
          <div className="absolute -right-12 -top-12 h-48 w-48 rounded-full bg-pink-500/10 blur-3xl" />
          <div className="absolute -bottom-12 -left-12 h-48 w-48 rounded-full bg-purple-500/10 blur-3xl" />
          <div className="relative">
            <div className="mx-auto flex h-24 w-24 items-center justify-center rounded-full bg-gradient-to-br from-pink-500/20 to-red-500/20 shadow-xl mb-8 animate-bounce-in">
              <Heart className="h-12 w-12 text-pink-500" />
            </div>
            <h2 className="text-3xl font-bold tracking-tight">Your wishlist is empty</h2>
            <p className="mt-4 text-muted-foreground max-w-sm mx-auto">
              Start adding items you love to your wishlist and save them for later.
            </p>
            <Link
              to="/"
              className="pk-btn pk-btn-primary pk-btn-shine mt-8 inline-flex h-14 px-10 text-base font-bold shadow-xl"
            >
              <Sparkles className="h-5 w-5" />
              Start Shopping
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="pk-container py-10">
      {/* Header */}
      <div className="flex flex-col gap-4 sm:flex-row sm:items-end sm:justify-between mb-8">
        <div>
          <h1 className="text-3xl font-bold tracking-tight md:text-4xl flex items-center gap-3">
            <Heart className="h-8 w-8 text-pink-500" />
            My Wishlist
          </h1>
          <p className="mt-2 text-muted-foreground">
            <span className="font-semibold text-foreground">{wishlistProducts.length}</span> {wishlistProducts.length === 1 ? 'item' : 'items'} saved for later
          </p>
        </div>
        <div className="flex gap-2">
          <select
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value as any)}
            className="pk-select h-11 w-[180px]"
          >
            <option value="recent">Recently Added</option>
            <option value="price-low">Price: Low to High</option>
            <option value="price-high">Price: High to Low</option>
            <option value="name">Name A-Z</option>
          </select>
          <button onClick={handleShare} className="pk-btn pk-btn-outline h-11 px-4 text-sm font-medium shadow-sm">
            <Share2 className="h-4 w-4" />
            Share
          </button>
          <button
            onClick={handleAddAllToCart}
            className="pk-btn pk-btn-primary pk-btn-shine h-11 px-5 text-sm font-medium shadow-sm"
          >
            <ShoppingCart className="h-4 w-4" />
            Add All to Cart
          </button>
          <button
            onClick={handleClearAll}
            className="pk-btn pk-btn-outline h-11 px-5 text-sm font-medium shadow-sm hover:bg-destructive/10 hover:text-destructive hover:border-destructive/50"
          >
            <Trash2 className="h-4 w-4" />
            Clear All
          </button>
        </div>
      </div>

      {/* Price Drop Alert Banner */}
      <div className="mb-6 rounded-2xl border border-amber-200/50 bg-gradient-to-r from-amber-50 to-orange-50 p-4 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="flex h-10 w-10 items-center justify-center rounded-full bg-amber-100">
            <Bell className="h-5 w-5 text-amber-600" />
          </div>
          <div>
            <div className="text-sm font-semibold">Price drop alert!</div>
            <div className="text-xs text-muted-foreground">3 items in your wishlist have dropped in price</div>
          </div>
        </div>
        <button className="pk-btn pk-btn-outline h-9 px-4 text-sm font-medium">
          View Drops
        </button>
      </div>

      {/* Wishlist Grid */}
      <div className="grid gap-5 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4">
        {wishlistProducts.map((product) => (
          <div key={product.id} className="pk-slide-up">
            <ProductCard product={{
              ...product,
              quantity: product.inStock ? 100 : 0,
              averageRating: product.rating,
              reviewCount: product.reviews,
              images: [product.image],
              category: { id: product.category, name: product.category }
            }} />
          </div>
        ))}
      </div>

      {/* Call to Action */}
      <div className="mt-12 rounded-3xl border bg-gradient-to-br from-primary/5 via-sky-500/5 to-emerald-500/5 p-8 text-center">
        <div className="mx-auto flex h-16 w-16 items-center justify-center rounded-full bg-gradient-to-br from-primary/20 to-sky-500/20 shadow-lg mb-4">
          <Sparkles className="h-8 w-8 text-primary" />
        </div>
        <h3 className="text-xl font-bold">You might also like</h3>
        <p className="mt-2 text-muted-foreground">Based on your wishlist, we think these products would be perfect for you</p>
        <Link
          to="/"
          className="pk-btn pk-btn-primary pk-btn-shine mt-6 inline-flex h-12 px-8 text-base font-semibold shadow-lg"
        >
          Explore More
          <MoveRight className="h-5 w-5 ml-2" />
        </Link>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { productsAPI } from '../../lib/products';
import type { Product } from '../../lib/products';
import { uploadAPI } from '../../lib/upload';
import { toast } from 'sonner';
import { Save, ArrowLeft, Image as ImageIcon, X, Loader2 } from 'lucide-react';
import api from '../../lib/api';

export default function ProductForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEditing = Boolean(id);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isLoading, setIsLoading] = useState(isEditing);
  const [categories, setCategories] = useState<{id: string, name: string}[]>([]);

  const [formData, setFormData] = useState<Partial<Product>>({
    name: '',
    description: '',
    price: 0,
    comparePrice: 0,
    sku: '',
    quantity: 0,
    status: 'ACTIVE',
    images: [],
    categoryId: '',
  });

  const [uploadingImage, setUploadingImage] = useState(false);

  useEffect(() => {
    // Fetch categories
    api.get('/api/categories').then(res => {
      setCategories(res.data);
      if (!isEditing && res.data.length > 0) {
        setFormData(prev => ({ ...prev, categoryId: res.data[0].id }));
      }
    }).catch(() => console.error("Categories fetch error"));

    if (isEditing && id) {
      productsAPI.getProduct(id).then(res => {
        setFormData(res as any);
      }).catch(() => {
        toast.error('Failed to load product');
        navigate('/seller/products');
      }).finally(() => {
        setIsLoading(false);
      });
    }
  }, [id, isEditing, navigate]);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setUploadingImage(true);
    try {
      const res = await uploadAPI.uploadImage(file);
      setFormData(prev => ({
        ...prev,
        images: [...(prev.images || []), res.url]
      }));
      toast.success('Image uploaded successfully');
    } catch (error) {
      toast.error('Failed to upload image. Max size is 5MB.');
    } finally {
      setUploadingImage(false);
    }
  };

  const removeImage = (indexToRemove: number) => {
    setFormData(prev => ({
      ...prev,
      images: prev.images?.filter((_, index) => index !== indexToRemove)
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.price || !formData.categoryId || !formData.sku) {
      toast.error('Please fill in all required fields');
      return;
    }

    setIsSubmitting(true);
    try {
      if (isEditing && id) {
        await productsAPI.updateProduct(id, formData);
        toast.success('Product updated successfully');
      } else {
        await productsAPI.createProduct(formData);
        toast.success('Product created successfully');
      }
      navigate('/seller/products');
    } catch (error: any) {
      toast.error(error.response?.data?.error?.[0]?.message || 'Failed to save product');
      console.error(error);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isLoading) return <div className="py-20 text-center text-muted-foreground flex flex-col items-center"><Loader2 className="animate-spin w-8 h-8 mb-4 opacity-50 text-primary" /> Loading product details...</div>;

  return (
    <div className="pk-container py-12 max-w-5xl">
      <div className="mb-8 flex items-center gap-4">
        <button onClick={() => navigate('/seller/products')} className="p-2 -ml-2 rounded-full hover:bg-muted/50 transition-colors text-muted-foreground">
          <ArrowLeft className="w-5 h-5" />
        </button>
        <div>
